#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    void quickSort(vector<int>& nums) {
        if (nums.size() <= 1) {
            return;
        }
        int pivot = nums[nums.size() / 2];
        vector<int> left, middle, right;
        for (int x : nums) {
            if (x < pivot) {
                left.push_back(x);
            } else if (x == pivot) {
                middle.push_back(x);
            } else {
                right.push_back(x);
            }
        }
        nums = left;
        nums.insert(nums.end(), middle.begin(), middle.end());
        nums.insert(nums.end(), right.begin(), right.end());
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    sol.quickSort(nums);
    for (int num : nums) {
        cout << num << '\n';
    }
    return 0;
}
